mapper.select:
SELECT upr.provider, upr.external_place_id, CAST(profile.user_id AS text) AS user_id, profile.display_name, profile.profile_image_url FROM social.user_follows follow JOIN preference.user_place_reactions upr ON upr.user_id = follow.following_user_id JOIN auth.user_profiles profile ON profile.user_id = follow.following_user_id WHERE follow.follower_user_id = CAST(#{currentUserId} AS uuid) AND follow.status = 'ACTIVE' AND follow.deleted_at IS NULL AND upr.reaction IN ('LIKE', 'SUPER_LIKE') AND (
(upr.provider = #{place.provider}::text AND upr.external_place_id = #{place.externalPlaceId})
) ORDER BY upr.provider, upr.external_place_id, CASE upr.reaction WHEN 'SUPER_LIKE' THEN 0 ELSE 1 END, upr.last_reacted_at DESC, profile.user_id
